class Solution {
public:
    string greatestLetter(string s) {
        set<char> upper, lower;
        for (char c : s) {
            if (isupper(c)) upper.insert(c);
            if (islower(c)) lower.insert(c);
        }
        for (char c = 'Z'; c >= 'A'; c--) {
            if (upper.count(c) && lower.count((char)(c - 'A' + 'a'))) return string(1, c);
        }
        return "";
    }
};
```
